import React, { useState } from 'react';
import { Button, Input, Modal, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { hrService } from '../../../services/ns/hrService';
import type { WorkShiftDto } from '../../../services/ns/models';
import styles from '../../../styles/erpPage.module.css';

const emptyShift = { code: '', name: '', startTime: '08:00', endTime: '17:00', workHours: 8 };

const CaLamViecPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const [shifts, setShifts] = useState<WorkShiftDto[]>([]);
  const [loading, setLoading] = useState(false);
  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState<WorkShiftDto | null>(null);
  const [form, setForm] = useState(emptyShift);
  const [saving, setSaving] = useState(false);
  const [deleteId, setDeleteId] = useState<string | null>(null);

  const load = () => {
    setLoading(true);
    hrService.getWorkShifts()
      .then(setShifts)
      .catch(err => dispatch(addToast({ message: err?.message ?? 'Lỗi tải ca làm việc', type: 'error' })))
      .finally(() => setLoading(false));
  };

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => { if (!cancelled) load(); }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const openAdd = () => {
    setEditing(null);
    setForm(emptyShift);
    setModalOpen(true);
  };

  const openEdit = (r: WorkShiftDto) => {
    setEditing(r);
    setForm({
      code: r.code,
      name: r.name,
      startTime: r.startTime?.slice(0, 5) ?? '08:00',
      endTime: r.endTime?.slice(0, 5) ?? '17:00',
      workHours: r.workHours,
    });
    setModalOpen(true);
  };

  const handleSave = async () => {
    if (!form.code.trim() || !form.name.trim()) {
      dispatch(addToast({ message: 'Vui lòng nhập mã và tên ca', type: 'error' }));
      return;
    }
    setSaving(true);
    try {
      if (editing) {
        await hrService.updateWorkShift(editing.id, { ...form, isActive: editing.isActive });
        dispatch(addToast({ message: 'Cập nhật ca làm việc thành công', type: 'success' }));
      } else {
        await hrService.createWorkShift(form);
        dispatch(addToast({ message: 'Tạo ca làm việc thành công', type: 'success' }));
      }
      setModalOpen(false);
      load();
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Lưu thất bại', type: 'error' }));
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (id: string) => {
    try {
      await hrService.deleteWorkShift(id);
      dispatch(addToast({ message: 'Xóa ca làm việc thành công', type: 'success' }));
      setDeleteId(null);
      load();
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Xóa thất bại', type: 'error' }));
    }
  };

  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}>
          <h1 className={styles.title}><i className="fas fa-business-time" /> Danh mục ca làm việc</h1>
        </div>
        <div className={styles.headerActions}>
          <Button variant="primary" onClick={openAdd}><i className="fas fa-plus" /> Thêm ca</Button>
        </div>
      </div>

      <div className={styles.tableCard}>
        {loading ? (
          <div className={styles.loading}><i className="fas fa-spinner fa-spin" /> Đang tải...</div>
        ) : shifts.length === 0 ? (
          <div className={styles.empty}><i className="fas fa-inbox" /><p>Chưa có ca làm việc</p></div>
        ) : (
          <div className={styles.tableWrapper}>
            <table className={styles.table}>
              <thead>
                <tr>
                  <th>Mã ca</th>
                  <th>Tên ca</th>
                  <th>Giờ vào</th>
                  <th>Giờ ra</th>
                  <th className={styles.colRight}>Giờ công</th>
                  <th>Trạng thái</th>
                  <th className={styles.colActions}></th>
                </tr>
              </thead>
              <tbody>
                {shifts.map(r => (
                  <tr key={r.id}>
                    <td><code>{r.code}</code></td>
                    <td>{r.name}</td>
                    <td>{r.startTime?.slice(0, 5)}</td>
                    <td>{r.endTime?.slice(0, 5)}</td>
                    <td className={styles.colRight}>{r.workHours}</td>
                    <td>
                      <span className={r.isActive ? styles.tagSuccess : styles.tagDefault}>
                        {r.isActive ? 'Hoạt động' : 'Tắt'}
                      </span>
                    </td>
                    <td className={styles.colActions}>
                      <button type="button" className={styles.actionBtn} onClick={() => openEdit(r)}><i className="fas fa-edit" /></button>
                      {deleteId === r.id ? (
                        <>
                          <button type="button" className={`${styles.actionBtn} ${styles.actionBtnDanger}`} onClick={() => handleDelete(r.id)}><i className="fas fa-check" /></button>
                          <button type="button" className={styles.actionBtn} onClick={() => setDeleteId(null)}><i className="fas fa-times" /></button>
                        </>
                      ) : (
                        <button type="button" className={`${styles.actionBtn} ${styles.actionBtnDanger}`} onClick={() => setDeleteId(r.id)}><i className="fas fa-trash" /></button>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      <Modal isOpen={modalOpen} onClose={() => setModalOpen(false)} title={editing ? 'Sửa ca làm việc' : 'Thêm ca làm việc'}>
        <div className={styles.modalBody}>
          <div className={styles.field}>
            <label className={styles.label}>Mã ca *</label>
            <Input value={form.code} onChange={e => setForm(f => ({ ...f, code: e.target.value }))} disabled={!!editing} />
          </div>
          <div className={styles.field}>
            <label className={styles.label}>Tên ca *</label>
            <Input value={form.name} onChange={e => setForm(f => ({ ...f, name: e.target.value }))} />
          </div>
          <div className={styles.formGrid}>
            <div className={styles.field}>
              <label className={styles.label}>Giờ vào</label>
              <Input type="time" value={form.startTime} onChange={e => setForm(f => ({ ...f, startTime: e.target.value }))} />
            </div>
            <div className={styles.field}>
              <label className={styles.label}>Giờ ra</label>
              <Input type="time" value={form.endTime} onChange={e => setForm(f => ({ ...f, endTime: e.target.value }))} />
            </div>
            <div className={styles.field}>
              <label className={styles.label}>Giờ công</label>
              <Input type="number" value={String(form.workHours)} onChange={e => setForm(f => ({ ...f, workHours: Number(e.target.value) }))} />
            </div>
          </div>
          <div className={styles.modalActions}>
            <Button variant="secondary" onClick={() => setModalOpen(false)}>Huỷ</Button>
            <Button variant="primary" onClick={handleSave} disabled={saving}>{saving ? 'Đang lưu...' : 'Lưu'}</Button>
          </div>
        </div>
      </Modal>
    </div>
  );
};

export default CaLamViecPage;
